def asal_bul(n):
  asal = [True]*(n+1)
  asal[0]=asal[1]=False
  for i in range(2,int(n**0.5)+1):
    if asal[i]:
      for j in range(i*i,n+1,i): asal[j]=False
  return [i for i in range(n+1) if asal[i]]
