def merge_sort(a):
  if len(a)<=1: return a
  o = len(a)//2
  return merge(merge_sort(a[:o]), merge_sort(a[o:]))
def merge(l,r):
  s=[]; i=j=0
  while i<len(l) and j<len(r):
    if l[i]<=r[j]: s.append(l[i]); i+=1
    else: s.append(r[j]); j+=1
  return s+l[i:]+r[j:]
